        "userEmail", user.getEmail(),
        "userRole", user.getRole().name()
    );
    session.sendMessage(new TextMessage(objectMapper.writeValueAsString(response)));

    log.info("User authenticated: {} ({})", user.getEmail(), user.getRole());

